export default (images) => {
    const projects = [
        {
            img: 'gatsby-mui-blog.png',
            title: 'Gatsby Material UI Blog',
            description: 'projects_page.gatsbyMaterialUiBlogDescription',
            url: 'https://github.com/blopa/gatsby-material-ui-blog-starter',
        },
        {
            img: 'contract-builder.png',
            title: 'Contract Builder',
            description: 'projects_page.contractBuilderDescription',
            url: 'https://github.com/blopa/Contract-Builder',
        },
        {
            img: 'resume-builder.png',
            title: 'Resume Builder',
            description: 'projects_page.resumeBuilderDescription',
            url: 'https://github.com/blopa/Resume-Builder',
        },
        {
            img: 'magento-chatbot.png',
            title: 'Magento Chatbot',
            description: 'projects_page.magentoChatbotDescription',
            url: 'https://github.com/blopa/Magento-Chatbot',
        },
        {
            img: 'jam-stack-shortener.jpg',
            title: 'JAMStack URL Shortener',
            description: 'projects_page.jamStackSortenerDescription',
            url: 'https://github.com/blopa/jamstack-url-shortener',
        },
        {
            img: 'gotinha.jpg',
            title: 'Gotinha (Phaser)',
            description: 'projects_page.gotinhaDescription',
            url: 'https://github.com/blopa/gotinha',
        },
    ];

    return images.map((image) => ({
        ...projects.find(
            (project) => image.childImageSharp.fixed.src.includes(project.img)
        ),
        img: image,
    }))
        .filter(
            (project) => project.img
                && project.title
                && project.description
                && project.url
        );
};
