import React, { useMemo } from 'react';
import { graphql, useStaticQuery } from 'gatsby';
import { Card, CardHeader, Grid } from '@material-ui/core';
import { makeStyles } from '@material-ui/core/styles';
import Image from 'gatsby-image';
import classNames from 'classnames';
import getProjects from '../data/projects';

const useStyles = makeStyles((theme) => ({
    projectPageWrapper: {
        padding: '15px 0',
    },
    projectWrapper: {
        [theme.breakpoints.up(760)]: {
            width: '250px !important', // TODO
        },
        [theme.breakpoints.up('xs')]: {
            width: '50%',
        },
        [theme.breakpoints.down('xs')]: {
            width: '100%',
        },
    },
    projectCardWrapper: {
        [theme.breakpoints.up(760)]: {
            width: 'initial !important', // TODO
        },
        [theme.breakpoints.up('xs')]: {
            width: '100%',
        },
        [theme.breakpoints.down('xs')]: {
            width: '100%',
        },
        '&:hover': {
            opacity: 0.7,
        },
    },
    projectImage: {
        [theme.breakpoints.up(760)]: {
            width: 'initial !important', // TODO
        },
        [theme.breakpoints.up('xs')]: {
            width: 'calc(100% - 20px) !important',
        },
        [theme.breakpoints.down('xs')]: {
            width: 'calc(100% - 20px) !important',
        },
        margin: '10px 10px 0',
        borderRadius: '5px 5px 0 0',
    },
    projectLink: {
        textDecoration: 'none',
        boxShadow: 'none',
    },
}));

const ProjectsThumbnailsList = ({ quantity, className = null }) => {
    const data = useStaticQuery(graphql`
        query ProjectsThumbnailsListQuery {
            contractBuilder: file(
                absolutePath: { regex: "/contract-builder.png/" }
            ) {
                childImageSharp {
                    fixed(width: 200, height: 200) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            resumeBuilder: file(
                absolutePath: { regex: "/resume-builder.png/" }
            ) {
                childImageSharp {
                    fixed(width: 200, height: 200) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            magentoChatbot: file(
                absolutePath: { regex: "/magento-chatbot.png/" }
            ) {
                childImageSharp {
                    fixed(width: 200, height: 200) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            gatsbyMaterialUiBlog: file(
                absolutePath: { regex: "/gatsby-mui-blog.png/" }
            ) {
                childImageSharp {
                    fixed(width: 200, height: 200) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            jamStackSortner: file(
                absolutePath: { regex: "/jam-stack-shortener.jpg/" }
            ) {
                childImageSharp {
                    fixed(width: 200, height: 200) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
            gotinha: file(
                absolutePath: { regex: "/gotinha.jpg/" }
            ) {
                childImageSharp {
                    fixed(width: 200, height: 200) {
                        ...GatsbyImageSharpFixed
                    }
                }
            }
        }
    `);

    const classes = useStyles();
    let projectsData = useMemo(
        () => getProjects(Object.values(data)), [data]
    );

    if (quantity) {
        projectsData = projectsData.slice(0, quantity);
    }

    return (
        <div
            className={classNames(className, classes.projectPageWrapper)}
        >
            <Grid
                container
                spacing={2}
                direction="row"
                justify="flex-start"
                alignItems="flex-start"
            >
                {projectsData.map((elem) => (
                    <Grid
                        item
                        key={elem.url}
                        className={classes.projectWrapper}
                    >
                        <Card
                            className={classes.projectCardWrapper}
                        >
                            <a
                                className={classes.projectLink}
                                href={elem.url}
                                rel="noreferrer"
                                target="_blank"
                                title={elem.title}
                            >
                                <Image
                                    className={classes.projectImage}
                                    fixed={elem.img.childImageSharp.fixed}
                                />
                            </a>
                            <CardHeader
                                title={elem.title}
                            />
                        </Card>
                    </Grid>
                ))}
            </Grid>
        </div>
    );
};

export default ProjectsThumbnailsList;
