import React, { useMemo } from 'react';
import { makeStyles } from '@material-ui/core/styles';
import { Divider, Typography } from '@material-ui/core';
import { useIntl } from 'gatsby-plugin-intl';

// Utils
import { getAlternateLangLinks } from '../utils/gatsby-frontend-helpers';

// Components
import Layout from '../components/Layout';
import SEO from '../components/SEO';
import Link from '../components/Link';
import SimplePostsList from '../components/SimplePostsList';
import ProjectsThumbnailsList from '../components/ProjectsThumbnailsList';

const useStyles = makeStyles((theme) => ({
    simplePostsListWrapper: {
        marginBottom: '10px',
        padding: '0 5px',
    },
    recentPostsText: {
        margin: '15px 0',
    },
    projectsText: {
        margin: '10px 0',
    },
    projectsWrapper: {
        padding: '15px 5px',
    },
    seeMoreText: {
        padding: '10px 0',
    },
}));

const HomePage = ({ location, data, pageContext }) => {
    const posts = data.allMarkdownRemark.edges;
    // const posts = [];
    const classes = useStyles();
    const intl = useIntl();
    const alternateLangLinks = useMemo(
        () => getAlternateLangLinks(pageContext, data.site.siteMetadata.siteUrl),
        [data.site.siteMetadata.siteUrl, pageContext]
    );

    return (
        <Layout>
            <SEO
                lang={intl.locale}
                pathname={location?.pathname}
                title={intl.formatMessage({ id: 'home' })}
                keywords={[
                    intl.formatMessage({ id: 'seo_keywords.personal_projects' }),
                    intl.formatMessage({ id: 'seo_keywords.personal_blog' }),
                    intl.formatMessage({ id: 'seo_keywords.games' }),
                    intl.formatMessage({ id: 'seo_keywords.development' }),
                    intl.formatMessage({ id: 'seo_keywords.es6' }),
                    intl.formatMessage({ id: 'seo_keywords.javascript' }),
                    intl.formatMessage({ id: 'seo_keywords.developer' }),
                    intl.formatMessage({ id: 'seo_keywords.tips' }),
                    intl.formatMessage({ id: 'seo_keywords.lifehacks' }),
                    intl.formatMessage({ id: 'seo_keywords.travels' }),
                    intl.formatMessage({ id: 'seo_keywords.reviews' }),
                ]}
                alternateLangLinks={alternateLangLinks}
            />
            <Typography
                className={classes.recentPostsText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: 'recent_posts' })}
            </Typography>
            <SimplePostsList
                className={classes.simplePostsListWrapper}
                posts={posts}
                quantity={5}
                locale={intl.locale}
            />
            <Link to="/blog">
                <Typography
                    color="textPrimary"
                    variant="overline"
                >
                    {intl.formatMessage({ id: 'see_more' })}
                </Typography>
            </Link>
            <Divider />
            <Typography
                className={classes.projectsText}
                color="textPrimary"
                variant="h4"
            >
                {intl.formatMessage({ id: 'projects_page.title' })}
            </Typography>
            <ProjectsThumbnailsList
                className={classes.projectsWrapper}
                quantity={4}
            />
        </Layout>
    );
};

export default HomePage;
